<?php namespace App\Repositories\Student;use App\Repositories\BaseRepository;use App\Models\Student\StudentParent;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class StudentParentRepository extends BaseRepository{    public function __construct(StudentParent $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudentId(int $studentId): Collection    {        return $this->query()->where('student_id', $studentId)->get();    }    public function findByParentId(int $parentId): Collection    {        return $this->query()->where('parent_id', $parentId)->get();    }    public function getEmergencyContacts(int $studentId): Collection    {        return $this->query()->where('student_id', $studentId)->where('is_emergency_contact', true)->get();    }    public function searchParents(string $keyword): Collection    {        return $this->query()->whereHas('parent', function ($q) use ($keyword) {            $q->where('first_name', 'like', "%{$keyword}%")->orWhere('last_name', 'like', "%{$keyword}%")->orWhere('email', 'like', "%{$keyword}%");        })->get();    }}